import numpy as np

def update_edge_distance(edge_distance, local_opt_tour, edge_n_used):
    updated_edge_distance = np.copy(edge_distance)

    for i in range(len(edge_distance)):
        for j in range(len(edge_distance)):
            if edge_n_used[i, j] == 0 and i != j:
                unused_edges_i = np.where(edge_n_used[i] == 0)[0]
                unused_edges_j = np.where(edge_n_used[j] == 0)[0]

                penalize_i = len(np.intersect1d(unused_edges_i, np.where(edge_n_used[local_opt_tour[i]] == 0)))
                penalize_j = len(np.intersect1d(unused_edges_j, np.where(edge_n_used[local_opt_tour[j]] == 0)))

                updated_edge_distance[i, j] += penalize_i + penalize_j

    return updated_edge_distance
